#include <iostream>
#include <sstream>
#include <string>

class Complex {
private:
    double real;
    double imag;

public:
    Complex(double r = 0.0, double i = 0.0) : real(r), imag(i) {}
    friend std::ostream& operator<<(std::ostream& os, const Complex& c);
};

std::ostream& operator<<(std::ostream& os, const Complex& c) {
    os << "(" << c.real << " + " << c.imag << "i)";
    return os;
}

int main() {
    std::stringstream ss;
    std::streambuf* oldCout = std::cout.rdbuf();

    // Test Case 1
    std::cout.rdbuf(ss.rdbuf());
    Complex c_tc1(3.0, 4.0);
    std::cout << c_tc1;
    std::cout.rdbuf(oldCout);
    std::cout << ss.str() << "TEST_CASE_SEPARATOR";
    ss.str(""); ss.clear();

    // Test Case 2
    std::cout.rdbuf(ss.rdbuf());
    Complex c_tc2(-1.0, -2.5);
    std::cout << c_tc2;
    std::cout.rdbuf(oldCout);
    std::cout << ss.str() << "TEST_CASE_SEPARATOR";
    ss.str(""); ss.clear();

    // Test Case 3
    std::cout.rdbuf(ss.rdbuf());
    Complex c_tc3(0.0, 0.0);
    std::cout << c_tc3;
    std::cout.rdbuf(oldCout);
    std::cout << ss.str();
    ss.str(""); ss.clear();

    return 0;
}
